const $ = cheerio.load(top250movies);

const movies = $("li.ipc-metadata-list-summary-item");

const final_data = [];

movies.each(function (index, element) {
  var title = $(element)
    .find("h3")
    .text()
    .trim();


  var title_without_rank = title.replace(/\d+./g,'').trim();


  const rank = index+1; 
  const rate = $(element).find('.ipc-rating-star--rating').text().trim();
  const price = $(element).find(".price").text().trim();
  const image = $(element).find("img").attr('src');
  const link = $(element).find("a").attr('href');

  var imdb_id = link.match(/(tt)\d+/);

  const image_bigger = image.replace(/_V1[\s\S][^.jpg]+/, 'UX500');

  // Push each product as an object with title and price to the product_data array
  final_data.push({ rank, rate, title: title_without_rank, image: image_bigger, id: imdb_id[0] });
});

// console.log('data: ', final_data);

fs.writeFileSync('top250series.json', JSON.stringify(final_data, null, 2))


